const src = $json && typeof $json === 'object' ? $json : {};
let body = src.body && typeof src.body === 'object' ? src.body : src;
if (typeof body.payload === 'string') {
  try { body = JSON.parse(body.payload); } catch (_) {}
}
if (body.payload && typeof body.payload === 'object') body = body.payload;

const clean = (value) => String(value ?? '').trim();
const toInt = (value) => {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? Math.trunc(n) : null;
};

const cf = body.clientes_finales && typeof body.clientes_finales === 'object' ? body.clientes_finales : {};
const c = body.citas && typeof body.citas === 'object' ? body.citas : {};

const payload = {
  barberia_id: toInt(c.barberia_id || c.id_barberia || body.barberia_id || body.id_barberia),
  slug: clean(c.slug || body.slug),
  servicio_id: toInt(c.servicio_id || c.id_servicio || body.servicio_id || body.id_servicio),
  barbero_id: toInt(c.barbero_id || c.id_barbero || body.barbero_id || body.id_barbero),
  fecha: clean(c.fecha || body.fecha),
  hora: clean(c.hora || c.hora_inicio || body.hora || body.hora_inicio),
  cliente_nombre: clean(cf.nombre || cf.nombre_completo || body.cliente_nombre || body.nombre),
  cliente_tel: clean(cf.telefono || cf.celular || body.cliente_tel || body.telefono),
  cliente_email: clean(cf.email || body.cliente_email || body.email),
  notas: clean(c.notas || body.notas)
};

if ((!payload.barberia_id && !payload.slug) || !payload.servicio_id || !payload.barbero_id || !payload.fecha || !payload.hora || !payload.cliente_nombre || !payload.cliente_tel) {
  return [{
    json: {
      ok: false,
      code: 'datos_invalidos',
      status_code: 400,
      message: 'Faltan datos obligatorios para reservar.',
      data: payload
    }
  }];
}

return [{ json: { ok: true, payload } }];

const first = $input.first().json || {};
if (first.error) {
  return [{
    json: {
      ok: false,
      code: 'error_postgres',
      message: first.error.message || 'Error creando reserva en PostgreSQL.',
      data: { error: first.error.message || first.error },
      status_code: 500
    }
  }];
}
const result = first.result || first.ba_reservas_public_create || first;
return [{
  json: {
    ok: Boolean(result.ok),
    code: result.code || (result.ok ? 'reserva_creada' : 'datos_invalidos'),
    message: result.message || '',
    data: result.data || {},
    status_code: result.ok ? 200 : 400
  }
}];

const src = $json && typeof $json === 'object' ? $json : {};
let body = src.body && typeof src.body === 'object' ? src.body : src;
if (typeof body.payload === 'string') {
  try { body = JSON.parse(body.payload); } catch (e) {}
}
if (body.payload && typeof body.payload === 'object') body = body.payload;

const clean = (v) => (v ?? '').toString().trim();
const toInt = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
};

const cf = body.clientes_finales && typeof body.clientes_finales === 'object' ? body.clientes_finales : {};
const c = body.citas && typeof body.citas === 'object' ? body.citas : {};

const out = {
  documento: clean(cf.documento),
  nombre_completo: clean(cf.nombre_completo || cf.nombre),
  telefono: clean(cf.telefono || cf.celular),
  email: clean(cf.email),
  id_barberia: toInt(c.id_barberia) || 1,
  id_barbero: toInt(c.id_barbero),
  id_servicio: toInt(c.id_servicio),
  fecha: clean(c.fecha),
  hora: clean(c.hora),
  estado: clean(c.estado || 'confirmada'),
  notas: clean(c.notas),
  created_at: new Date().toISOString()
};

if (!out.nombre_completo || !out.telefono || !out.fecha || !out.hora) {
  return [{ json: { ok: "false", status_code: 400, message: 'Faltan campos obligatorios para reservar.', payload: out } }];
}

return [{ json: { ok: "true", payload: out } }];

const schemaRows = $input.all().map(i => i.json);
const normalized = $('Normalize payload').first().json;
const p = normalized.payload || {};

const colsCF = new Set(schemaRows.filter(r => r.table_name === 'clientes_finales').map(r => r.column_name));
const colsCitas = new Set(schemaRows.filter(r => r.table_name === 'citas').map(r => r.column_name));

const pick = (set, list) => list.find(c => set.has(c)) || null;
const params = [];
const add = (v) => { params.push(v); return `$${params.length}`; };

const cfNombreCol = pick(colsCF, ['nombre_completo', 'nombre']);
const cfTelCol = pick(colsCF, ['telefono', 'celular']);
if (!cfNombreCol || !cfTelCol) {
  return [{ json: { ok: "false", status_code:500, message:'No se encontraron columnas m?nimas en clientes_finales.', debug:{cfNombreCol, cfTelCol} } }];
}

const cfPairs = [];
if (colsCF.has('documento')) cfPairs.push(['documento', p.documento || null]);
cfPairs.push([cfNombreCol, p.nombre_completo]);
cfPairs.push([cfTelCol, p.telefono]);
if (colsCF.has('email')) cfPairs.push(['email', p.email || null]);
if (colsCF.has('id_barberia')) cfPairs.push(['id_barberia', p.id_barberia || 1]);
if (colsCF.has('barberia_id')) cfPairs.push(['barberia_id', p.id_barberia || 1]);
if (colsCF.has('created_at')) cfPairs.push(['created_at', p.created_at]);

const cfPk = pick(colsCF, ['id', 'cliente_id', 'id_cliente', 'id_cliente_final']);
const cfCols = cfPairs.map(x => x[0]).join(', ');
const cfVals = cfPairs.map(x => add(x[1])).join(', ');
const cfReturning = cfPk ? ` RETURNING ${cfPk}` : '';

const citaPairs = [];
const citaBarberiaCol = pick(colsCitas, ['id_barberia', 'barberia_id']);
if (citaBarberiaCol) citaPairs.push([citaBarberiaCol, p.id_barberia || 1]);

const citaBarberoCol = pick(colsCitas, ['id_barbero', 'barbero_id']);
if (citaBarberoCol) citaPairs.push([citaBarberoCol, p.id_barbero]);

const citaServicioCol = pick(colsCitas, ['id_servicio', 'servicio_id']);
if (citaServicioCol) citaPairs.push([citaServicioCol, p.id_servicio]);

const citaClienteCol = pick(colsCitas, ['id_cliente_final', 'cliente_final_id', 'id_cliente', 'cliente_id']);


const clienteNombreCol = pick(colsCitas, ['cliente_nombre', 'nombre_cliente']);
if (clienteNombreCol) citaPairs.push([clienteNombreCol, p.nombre_completo]);

const clienteTelCol = pick(colsCitas, ['cliente_tel', 'telefono_cliente']);
if (clienteTelCol) citaPairs.push([clienteTelCol, p.telefono]);

const fechaCol = pick(colsCitas, ['fecha', 'fecha_cita']);
const horaCol = pick(colsCitas, ['hora_inicio', 'hora', 'hora_cita']);
const fechaHoraCol = pick(colsCitas, ['fecha_hora', 'fecha_hora_cita', 'inicio', 'scheduled_at']);
if (fechaHoraCol) {
  const dt = (p.fecha && p.hora) ? `${p.fecha}T${p.hora}:00` : null;
  citaPairs.push([fechaHoraCol, dt]);
} else {
  if (fechaCol) citaPairs.push([fechaCol, p.fecha]);
  if (horaCol) citaPairs.push([horaCol, p.hora]);
}

const estadoCol = pick(colsCitas, ['estado', 'status']);
if (estadoCol) citaPairs.push([estadoCol, p.estado || 'confirmada']);

const notasCol = pick(colsCitas, ['notas', 'nota', 'observaciones', 'observacion']);
if (notasCol) citaPairs.push([notasCol, p.notas || null]);

if (colsCitas.has('created_at')) citaPairs.push(['created_at', p.created_at]);

if (!citaPairs.length) {
  return [{ json: { ok: "false", status_code:500, message:'No fue posible mapear columnas de citas.', debug:{ colsCitas:[...colsCitas] } } }];
}

const citaCols = [];
const citaVals = [];
for (const [col, val] of citaPairs) {
  citaCols.push(col);
  citaVals.push(add(val));
}

if (citaClienteCol && cfPk) {
  citaCols.push(citaClienteCol);
  citaVals.push(`(SELECT ${cfPk} FROM ins_cliente LIMIT 1)`);
}

const citaPk = pick(colsCitas, ['id', 'cita_id']);
const citaReturning = citaPk ? ` RETURNING ${citaPk} AS cita_id` : ' RETURNING *';

const query = `WITH ins_cliente AS (INSERT INTO clientes_finales (${cfCols}) VALUES (${cfVals})${cfReturning}) INSERT INTO citas (${citaCols.join(', ')}) VALUES (${citaVals.join(', ')})${citaReturning};`;

return [{ json: { ok: "true", query, params } }];
